#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int low=1, high=N;
        int first=1;
        while(low<high){
            if(!first) printf(" ");
            printf("%d",high);
            first=0;
            printf(" %d",low);
            high--; low++;
        }
        if(low==high){
            if(!first) printf(" ");
            printf("%d",low);
        }
        printf("\n");
    }
    return 0;
}

