const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let low = 1, high = N;
  let parts = [];
  while (low < high) {
    parts.push(String(high));
    parts.push(String(low));
    high--; low++;
  }
  if (low === high) parts.push(String(low));
  out.push(parts.join(' '));
}
